import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { cartAPI } from '../services/api';
import { useAuth } from './AuthContext';

const CartContext = createContext(null);

export function CartProvider({ children }) {
  const { user, isLoggedIn } = useAuth();
  const [cart, setCart]       = useState(null);
  const [loading, setLoading] = useState(false);

  // JWT from backend only has sub (email) + role — no userId
  // So fall back to user.email as the cart identifier
  const getUserId = () => user?.id || user?.email || null;

  const fetchCart = useCallback(async () => {
    const userId = getUserId();
    if (!isLoggedIn() || !userId) return;
    setLoading(true);
    try {
      const res = await cartAPI.getCart(userId);
      setCart(res.data);
    } catch {
      setCart(null);
    } finally {
      setLoading(false);
    }
  }, [user, isLoggedIn]);

  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  const addItem = async (book, quantity = 1) => {
    const userId = getUserId();
    if (!isLoggedIn() || !userId) throw new Error('Login required');
    const payload = {
      bookId:    book.id,
      bookTitle: book.title,
      price:     book.price,
      quantity,
    };
    const res = await cartAPI.addItem(userId, payload);
    setCart(res.data);
    return res.data;
  };

  const removeItem = async (itemId) => {
    const userId = getUserId();
    if (!userId) return;
    const res = await cartAPI.removeItem(userId, itemId);
    setCart(res.data);
    return res.data;
  };

  const updateQuantity = async (itemId, quantity) => {
    const userId = getUserId();
    if (!userId) return;
    const res = await cartAPI.updateQuantity(userId, itemId, { quantity });
    setCart(res.data);
    return res.data;
  };

  const clearCart = async () => {
    const userId = getUserId();
    if (!userId) return;
    const res = await cartAPI.clearCart(userId);
    setCart(res.data);
    return res.data;
  };

  const totalItems = cart?.totalItems ?? 0;
  const totalPrice = cart?.totalPrice ?? 0;
  const cartItems  = cart?.items      ?? [];
  const isInCart   = (bookId) => cartItems.some(item => item.bookId === bookId);

  return (
    <CartContext.Provider value={{
      cart, loading, cartItems, totalItems, totalPrice,
      addItem, removeItem, updateQuantity, clearCart, fetchCart, isInCart,
    }}>
      {children}
    </CartContext.Provider>
  );
}

export const useCart = () => useContext(CartContext);
